import sys
from bisect import bisect_left, insort

input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))

    # Coordinate compress
    sorted_vals = sorted(set(a))
    rank = {v: i+1 for i, v in enumerate(sorted_vals)}
    m = len(sorted_vals)

    # Fenwick tree
    bit = [0] * (m + 2)

    def update(i):
        while i <= m:
            bit[i] += 1
            i += i & (-i)

    def query(i):
        s = 0
        while i > 0:
            s += bit[i]
            i -= i & (-i)
        return s

    def count_less(v):
        r = rank[v]
        return query(r - 1)

    def count_greater(v):
        r = rank[v]
        total = query(m)
        return total - query(r)

    ans = 0
    for x in a:
        cl = count_less(x)
        cg = count_greater(x)
        ans += min(cl, cg)
        update(rank[x])

    print(ans)

t = int(input())
for _ in range(t):
    solve()
